@module samplePage  src=samplePage.lua  loc=75  sha=1278d64  mode=chunk
@deps cm, ds, cmgr, chrome, gui, facade

# Imports
  @require fs = 'fs'  @ 11
      @contract  builds the substack (sm/sv local, only sv leaves); lifecycle drives sm/sv directly
      @contract  owns its active track: the renderer's picker sets sv; probe take comes from the arrange facade in tick
      @contract  render hooks delegate to sampleRender
  @require util = 'util'  @ 12

# Constructed sub-instances
  @construct sm = util.instantiate('sampleManager')  @ 25
  @construct sv = util.instantiate('sampleView')  @ 26
  @construct sr = util.instantiate('sampleRender')  @ 27

# Private state
  @state sp = {}  @ 30

# Private functions
  @fn arrange()  @ 21

# Public API (sp:*)
  -- Page lifecycle (track ops on sv, JSFX poll on sm)
  @api sp:bind()  @ 39
      -- The shared cm is re-keyed by whichever page is active, so re-assert ours each
      -- time even when sv already remembers a track -- a prior tracker unbind nulled it.
      @contract  bind re-keys cm to the page's track on every activation (seeds a default on the first)
  @api sp:setTrack(track)  @ 49
      @contract  setTrack re-keys cm to the given track via sv; the sample facade and the picker drive it
  @api sp:listTracks()  @ 54
      @contract  listTracks proxies sm:listTracks via sv — coord queries this to seed its active sampler track on first activation
  @api sp:unbind()  @ 57
      @contract  unbind reverts any preview-in-place but leaves cm and sv state alone — the next bind can resume on the same track
  @api sp:tick()  @ 60
      @contract  tick runs every frame; watchPath + sm:tick always; probeMode skipped if no current take
  -- Page interface — render delegates to the renderer
  @api sp:toolbarSegments()  @ 70
  @api sp:renderBody(ctx, w, h, dispatch)  @ 71
  @api sp:renderStatusBar(ctx)  @ 72
  @api sp:focusState()  @ 73

# Uses (outbound edges)
  @use call    facade.get  @ 21
  @use call    facade.publish  @ 67
  @use call    sampleManager.probeMode  @ 62
  @use call    sampleManager.tick  @ 64
  @use call    sampleManager.watchPath  @ 63
  @use call    sampleRender.closeTransients  @ 57
  @use call    sampleRender.focusState  @ 73
  @use call    sampleRender.renderBody  @ 71
  @use call    sampleRender.renderStatusBar  @ 72
  @use call    sampleRender.toolbarSegments  @ 70
  @use call    sampleView.getTrack  @ 40
  @use call    sampleView.listTracks  @ 42, 54
  @use call    sampleView.setTrack  @ 45, 50
  @use call    util.instantiate  @ 25, 26, 27
  @use require fs  @ 11
  @use require sampleManager  @ 25
  @use require sampleRender  @ 27
  @use require sampleView  @ 26
  @use require util  @ 12

# REAPER API surface
  @reaper ImGui_GetBuiltinPath
  @reaper MB
